import logging
from dataclasses import dataclass
from typing import Dict
import unittest

# Configure logging for production visibility
logging.basicConfig(level=logging.INFO, format='%(levelname)s: %(message)s')
logger = logging.getLogger("InventorySystem")

class InventoryError(Exception):
    """Base class for exceptions in this module."""
    pass

class InsufficientStockError(InventoryError):
    """Raised when an operation would result in negative stock."""
    pass

class InvalidInputError(InventoryError):
    """Raised when input parameters are invalid."""
    pass

@dataclass
class Item:
    """Data model representing an inventory item."""
    id: str
    name: str
    quantity: int

class InventoryManager:
    """Central registry for managing inventory stock levels."""

    def __init__(self, threshold: int = 5):
        self._inventory: Dict[str, Item] = {}
        self.threshold = threshold

    def add_item(self, item: Item) -> None:
        """Adds a new item to the inventory."""
        if item.id in self._inventory:
            raise InvalidInputError(f"Item ID {item.id} already exists.")
        if item.quantity < 0:
            raise InvalidInputError("Initial quantity cannot be negative.")
        self._inventory[item.id] = item

    def update_stock(self, item_id: str, delta: int) -> None:
        """Updates stock levels and triggers alerts if below threshold."""
        if item_id not in self._inventory:
            raise InvalidInputError(f"Item ID {item_id} not found.")

        item = self._inventory[item_id]
        new_quantity = item.quantity + delta

        if new_quantity < 0:
            raise InsufficientStockError(f"Operation failed: {item.name} would have negative stock.")

        item.quantity = new_quantity
        self._check_threshold(item)

    def _check_threshold(self, item: Item) -> None:
        """Private method to monitor stock levels."""
        if item.quantity < self.threshold:
            logger.warning(f"ALERT: Low stock for {item.name} (ID: {item.id}). Current: {item.quantity}")

class TestInventoryManager(unittest.TestCase):
    """Suite of unit tests for InventoryManager."""

    def setUp(self):
        self.manager = InventoryManager(threshold=5)
        self.manager.add_item(Item("A1", "Widget", 10))

    def test_add_item_success(self):
        item = Item("B2", "Gadget", 20)
        self.manager.add_item(item)
        self.assertEqual(self.manager._inventory["B2"].quantity, 20)

    def test_update_stock_success(self):
        self.manager.update_stock("A1", -2)
        self.assertEqual(self.manager._inventory["A1"].quantity, 8)

    def test_insufficient_stock_exception(self):
        with self.assertRaises(InsufficientStockError):
            self.manager.update_stock("A1", -15)

    def test_low_stock_alert(self):
        with self.assertLogs("InventorySystem", level="WARNING") as cm:
            self.manager.update_stock("A1", -6)
        self.assertTrue(any("Low stock" in output for output in cm.output))

if __name__ == "__main__":
    unittest.main()
